import anthropic, json

_classifier_client = anthropic.Anthropic()

SAFETY_SYSTEM = """You are a content safety classifier. Given a user message,
output JSON:
  { "category": "<one of: allowed|weapon_synthesis|csam|malware|hate_speech|self_harm|fraud|jailbreak|borderline>",
    "confidence": <0.0-1.0>,
    "reason": "<one sentence>" }

Focus on INTENT, not surface words. A chemistry question about detergents is allowed.
Respond ONLY with the JSON object."""

def llm_safety_classify(prompt: str) -> FilterResult:
    resp = _classifier_client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=120,
        messages=[{"role": "user", "content": prompt}],
        system=SAFETY_SYSTEM,
    )
    try:
        data = json.loads(resp.content[0].text)
        cat = PolicyCategory(data["category"])
        return FilterResult(
            allowed=cat not in DENY_SET,
            category=cat,
            confidence=data["confidence"],
            reason=data.get("reason", ""),
        )
    except Exception as e:
        # parse failure → conservative block
        return FilterResult(allowed=False, category=PolicyCategory.BORDERLINE,
                            confidence=0.5, reason=f"parse error: {e}")

def input_filter(prompt: str) -> FilterResult:
    """Full input filter: fast keyword check, then LLM classifier."""
    fast = keyword_filter(prompt)
    if not fast.allowed:
        return fast
    return llm_safety_classify(prompt)

from collections import deque
from dataclasses import dataclass, field

@dataclass
class SessionContext:
    session_id: str
    recent_categories: deque = field(default_factory=lambda: deque(maxlen=20))
    policy_strike_count: int = 0
    first_borderline_turn: int = -1
    turn_count: int = 0

    def record(self, result: FilterResult) -> None:
        self.turn_count += 1
        self.recent_categories.append(result.category)
        if result.category in DENY_SET:
            self.policy_strike_count += 1
        if result.category == PolicyCategory.BORDERLINE and self.first_borderline_turn < 0:
            self.first_borderline_turn = self.turn_count

    @property
    def escalation_risk(self) -> float:
        """Heuristic: risk score 0-1 based on recent session behaviour."""
        if self.policy_strike_count >= 3:
            return 1.0
        borderline_recent = sum(
            1 for c in self.recent_categories if c == PolicyCategory.BORDERLINE
        )
        return min(1.0, (self.policy_strike_count * 0.4) + (borderline_recent * 0.1))

_sessions: dict[str, SessionContext] = {}

def get_session(session_id: str) -> SessionContext:
    if session_id not in _sessions:
        _sessions[session_id] = SessionContext(session_id=session_id)
    return _sessions[session_id]

def session_aware_filter(session_id: str, prompt: str) -> FilterResult:
    """Combine per-message filter with session risk score."""
    ctx = get_session(session_id)
    result = input_filter(prompt)
    ctx.record(result)

    # Escalation override: flag borderline as deny if session risk is high
    if result.category == PolicyCategory.BORDERLINE and ctx.escalation_risk > 0.5:
        return FilterResult(allowed=False, category=PolicyCategory.BORDERLINE,
                            confidence=0.8, reason="elevated session risk")
    return result
